// Known-typo, defined: fixed lookup table only, no model guessing.
const LOOKUP = { 'gamil.com': 'gmail.com', 'outlok.com': 'outlook.com', 'yahooo.com': 'yahoo.com', 'hotmial.com': 'hotmail.com' };
const [, domain] = String($json.email).split('@');
const fixed = LOOKUP[String(domain).toLowerCase()];
if (!fixed) return [{ json: { ...$json, corrected: false } }];

const fs = require('fs');
const path = require('path');
const correctedEmail = $json.email.split('@')[0] + '@' + fixed;

let corrections = [];
const correctionPath = path.join('Working', $json.project_prefix, 'ai_corrected_contacts.json');
try { corrections = JSON.parse(fs.readFileSync(correctionPath, 'utf8')); } catch (e) {}
corrections.push({ contact_hash: $json.contact_hash, original_email: $json.email, corrected_email: correctedEmail, corrected_at: new Date().toISOString() });
fs.writeFileSync(correctionPath, JSON.stringify(corrections, null, 2), 'utf8');
// contacts.json itself stays untouched -- audit original preserved.

return [{ json: { ...$json, corrected: true, corrected_email: correctedEmail, resend_once: true } }];

// Shared escalation chain: search org site for one official address,
// send once; fails, one further address, send once; fails, stop and
// suppress. Used by hard_no_typo AND ooo-without-alternate.

const attempt = $json.escalation_attempt || 0;

if (attempt >= 2) {
  return [{ json: { ...$json, escalation_exhausted: true } }];
}

// In production this calls the same contact-research pattern (06) to
// find an official address; represented here as the escalation state
// machine, not a duplicated research implementation.
return [{ json: { ...$json, escalation_attempt: attempt + 1, escalation_exhausted: false } }];

// OOO circuit breaker: alternate-address resend fires at MOST ONCE per
// original send. If the reply provides no alternate, or the alternate
// itself fails, this falls into the SAME bounded escalation chain --
// never repeats discovery. Discovered alternates are NEVER promoted to
// tracked contacts (A8/B8) -- the loop-prevention mechanism.

const alreadyAttemptedOnce = $json.ooo_alternate_attempted === true;
if (alreadyAttemptedOnce) {
  return [{ json: { ...$json, route: 'escalation' } }]; // falls to the shared chain, no re-discovery
}

const alternate = $json.parsed_alternate_email || null;
if (alternate) {
  return [{ json: { ...$json, route: 'resend_once', target_email: alternate, ooo_alternate_attempted: true } }];
}
return [{ json: { ...$json, route: 'escalation' } }];

// Complaint or exhausted escalation -> Global DNC, automatic, no review.
const crypto = require('crypto');
const fs = require('fs');
const path = require('path');

const normalized = String($json.email).toLowerCase().trim().replace(/\+.*@/, '@');
const hash = crypto.createHash('sha256').update(normalized).digest('hex');

const dncPath = path.join('Shared', 'global_dnc.txt');
let existing = [];
try { existing = fs.readFileSync(dncPath, 'utf8').split('\n').filter(Boolean); } catch (e) {}
if (!existing.includes(hash)) {
  fs.appendFileSync(dncPath, hash + '\n', 'utf8');
}

return [{ json: { ...$json, dnc_written: true } }];
